mapper.select:
SELECT t.role_permission_id, t.role_id, t.permission_id, t.is_valid, r.role_id as r_role_id, r.role_name as r_role_name, r.is_valid as r_is_valid, p.permission_id as p_permission_id, p.permission_name as p_permission_name, p.permission_url as p_permission_url, p.is_valid as p_is_valid FROM role_permission t LEFT JOIN role r ON r.role_id = t.role_id LEFT JOIN permission p ON p.permission_id = t.permission_id
AND t.is_valid = 1
AND t.role_id = #{params.roleId}
AND t.permission_id = #{params.permissionId}
AND t.role_name LIKE CONCAT('%',#{params.roleNameLike},'%' )
AND p.permission_name LIKE CONCAT('%',#{params.permissionNameLike},'%' )
